import vex
from llama_stack_client import LlamaStackAgent

agent = LlamaStackAgent()

@ vex.verify({
    'policy': 'insurance-underwriting',
    'rules': [
        {'type': 'no-protected-classes', 'attributes': ['race', 'gender', 'age']},
        {'type': 'fairness-score', 'threshold': 0.8}
    ]
})
def process_underwriting(app_data):
    response = agent.invoke(f"Assess risk for: {app_data}")
    return response

# Usage
result = process_underwriting("Applicant: John Doe, zip 90210")

