            'denial_reason': {'type': 'string'},
            'citations': {'type': 'array'}
        }
    }
})
def process_claim(claim_data):
    response = agent.invoke(f"Evaluate claim: {claim_data}")
    return response

# Usage
result = process_claim("Auto claim #12345: rear-end collision")

